  { json: { correlationId: 'fake-prev-002', op: 'issue', provider: 'amego', orderId: 'o-002', invoiceNumber: 'AA00010002', status: 'issued', appliedAt: '2026-05-10T12:00:00.000Z' } },
  { json: { correlationId: 'fake-prev-003', op: 'void', provider: 'amego', orderId: 'o-001', invoiceNumber: 'AA00010001', status: 'voided', appliedAt: '2026-05-12T09:00:00.000Z' } },
  { json: { correlationId: 'fake-prev-004', op: 'allowance', provider: 'amego', orderId: 'o-002', invoiceNumber: 'AA00010002', status: 'allowed', appliedAt: '2026-05-15T15:00:00.000Z' } },
  { json: { correlationId: 'fake-prev-005', op: 'issue', provider: 'amego', orderId: 'o-003', invoiceNumber: 'AA00010003', status: 'issued', appliedAt: '2026-05-28T11:30:00.000Z' } }
];

const range = $node['Stamp previous month (Taipei)'].json;
const rows = $items().map(i => i.json).filter(r => {
  const t = (r.appliedAt || '').slice(0,10);
  return t >= range.rangeStart && t < range.rangeEndExclusive;
});
const headers = ['correlationId','op','provider','orderId','invoiceNumber','status','appliedAt'];
const escape = (v) => {
  const s = v == null ? '' : String(v);
  if (/[,"\n]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
};
const lines = [headers.join(',')];
for (const r of rows) lines.push(headers.map(h => escape(r[h])).join(','));
const counts = rows.reduce((acc,r) => { acc[r.op] = (acc[r.op]||0) + 1; return acc; }, {});
return [{ json: { correlationId: range.correlationId, yyyymm: range.yyyymm, csv: lines.join('\n'), rowCount: rows.length, counts } }];

